mapper.select:
SELECT f.artifact_id AS artifactId, a.title_zh AS titleZh, a.title_en AS titleEn, a.image_url AS imageUrl, f.group_name AS groupName, f.created_at AS createdAt FROM user_favorites f LEFT JOIN artifacts a ON f.artifact_id = a.id WHERE f.user_id = #{userId}
AND f.group_name = #{groupName}
ORDER BY f.created_at DESC LIMIT #{offset}, #{limit}
